#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#include "./main.h"
#include "./util/device/device.h"
#include "./util/timer/timer.h"

void setdevice(void) {
}

void checkCUDAError(const char *msg) {
	(void)msg;
}

void kernel_cpu(par_str par,
				dim_str dim,
				box_str* box,
				FOUR_VECTOR* rv,
				fp* qv,
				FOUR_VECTOR* fv)
{
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	if (dim.cores_arg > 0) {
		omp_set_num_threads(dim.cores_arg);
	}

	time1 = get_time();
	time2 = get_time();
	time3 = get_time();

	#pragma omp parallel for schedule(static)
	for (long bx = 0; bx < dim.number_boxes; bx++) {

		fp a2 = 2.0 * par.alpha * par.alpha;

		long first_i;
		FOUR_VECTOR* rA;
		FOUR_VECTOR* fA;
		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];

		int pointer;
		int k = 0;
		long first_j;
		FOUR_VECTOR* rB;
		fp* qB;
		int j = 0;
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		fp r2;
		fp u2;
		fp vij;
		fp fs;
		fp fxij;
		fp fyij;
		fp fzij;
		THREE_VECTOR d;

		first_i = box[bx].offset;

		rA = &rv[first_i];
		fA = &fv[first_i];

		for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
			rA_shared[i] = rA[i];
		}

		for (k = 0; k < (1 + box[bx].nn); k++) {

			if (k == 0) {
				pointer = (int)bx;
			}
			else {
				pointer = box[bx].nei[k - 1].number;
			}

			first_j = box[pointer].offset;

			rB = &rv[first_j];
			qB = &qv[first_j];

			for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
				rB_shared[i] = rB[i];
				qB_shared[i] = qB[i];
			}

			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {

					r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v - DOT(((FOUR_VECTOR)(rA_shared[wtx])), ((FOUR_VECTOR)(rB_shared[j])));
					u2 = a2 * r2;
					vij = exp(-u2);
					fs = 2 * vij;

					d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
					fxij = fs * d.x;
					d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
					fyij = fs * d.y;
					d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;
					fzij = fs * d.z;

					fA[wtx].v += (double)((fp)qB_shared[j] * vij);
					fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
					fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
					fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
				}
			}
		}
	}

	time4 = get_time();
	time5 = get_time();
	time6 = get_time();

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");

	printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: ALO\n",                    (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n",                (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: KERNEL\n",                     (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n",               (float)(time5 - time4) / 1000000, (float)(time5 - time4) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: FRE\n",                    (float)(time6 - time5) / 1000000, (float)(time6 - time5) / (float)(time6 - time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", (float)(time6 - time0) / 1000000);
}
